(22, 12, true, false, 'Item is certified no_beef. Contents are chicken, rice noodles, vegetables, and soy — no beef present. Satisfies no_beef.', '2026-06-03 10:11:35.828779+00:00'::timestamptz),
(22, 13, true, false, 'Item is certified no_beef. Contents are pork, rice vermicelli, salad and herbs — no beef present. Satisfies no_beef.', '2026-06-03 10:11:35.828779+00:00'::timestamptz),
