(266, 31, true, true, 'The item''s tweaks explicitly state ''Vegetarian option available on request'', and the base contents note ''no meat, seafood-free'', so the vegetarian tweak confirms a fully meat/seafood-free version is available.', '2026-06-03 10:14:10.151027+00:00'::timestamptz),
(266, 32, true, true, 'The anchovy dressing contains seafood, violating the vegetarian restriction. However, the tweaks state ''Can omit anchovy dressing on request'', which removes the offending ingredient, making it safe.', '2026-06-03 10:14:10.151027+00:00'::timestamptz),
(266, 33, true, true, 'The protein is listed as ''type unspecified'', which could be meat. However, the tweaks explicitly state ''Vegetarian option available on request'', which would replace the unspecified protein with a vegetarian alternative, making it safe.', '2026-06-03 10:14:10.151027+00:00'::timestamptz),
(266, 34, true, true, 'Contains grilled chicken (meat), but the tweaks explicitly state ''Vegetarian option available on request'', which removes the meat and makes it safe for a vegetarian student.', '2026-06-03 10:14:10.151027+00:00'::timestamptz),
(266, 35, false, false, 'Contains pulled pork, which is meat. No tweaks are available to remove it.', '2026-06-03 10:14:10.151027+00:00'::timestamptz),
(266, 36, true, true, 'Contains seasoned meat (protein unspecified), violating the vegetarian restriction. However, tweaks state ''Vegetarian option available on request (beans instead of meat)'', which directly replaces the meat, making it safe.', '2026-06-03 10:14:10.151027+00:00'::timestamptz),
(266, 37, true, true, 'Contains seasoned meat (protein unspecified), violating the vegetarian restriction. However, tweaks state ''Vegetarian option available on request (beans instead of meat)'', which directly replaces the meat, making it safe.', '2026-06-03 10:14:10.151027+00:00'::timestamptz),
(266, 38, false, false, 'Contains grilled chicken, which is meat. No tweaks are available to remove it.', '2026-06-03 10:14:10.151027+00:00'::timestamptz),
