INSERT INTO student_eligible_meals (enrolment_id, menu_item_id, eligible, needs_tweak, rationale, computed_at) VALUES
(270, 31, true, false, 'Item is certified no_beef and no_pork. Contents confirm no meat. Satisfies both required restrictions.', '2026-06-03 10:14:07.051373+00:00'::timestamptz),
(270, 32, true, false, 'Item is certified no_beef and no_pork. Contains anchovy dressing (seafood), but neither beef nor pork is present or required to be avoided beyond the student''s stated restrictions. Both restrictions are fully satisfied.', '2026-06-03 10:14:07.051373+00:00'::timestamptz),
(270, 33, false, false, 'Protein type is unspecified and explicitly flagged to treat as unsafe for beef/pork. Item is not certified for no_beef or no_pork. The vegetarian tweak could remove the protein concern, but the item is not certified for no_beef/no_pork even with the tweak, and the tweak''s effect on certification is not stated.', '2026-06-03 10:14:07.051373+00:00'::timestamptz),
(270, 34, true, false, 'Item is certified no_beef and no_pork. Contains grilled chicken only as protein. Both restrictions are fully satisfied.', '2026-06-03 10:14:07.051373+00:00'::timestamptz),
(270, 35, false, false, 'Contains pulled pork as a primary ingredient. This directly violates the no_pork restriction. No tweak is available to remove the pork.', '2026-06-03 10:14:07.051373+00:00'::timestamptz),
(270, 36, true, true, 'Seasoned meat protein is unspecified and flagged as unsafe for beef; item is not certified no_beef or no_pork. However, the stated vegetarian tweak (beans instead of meat) removes the unspecified meat entirely, making it safe for both no_beef and no_pork restrictions.', '2026-06-03 10:14:07.051373+00:00'::timestamptz),
(270, 37, true, true, 'Seasoned meat protein is unspecified and flagged as unsafe for beef; item is not certified no_beef or no_pork. However, the stated vegetarian tweak (beans instead of meat) removes the unspecified meat entirely, making it safe for both no_beef and no_pork restrictions.', '2026-06-03 10:14:07.051373+00:00'::timestamptz),
(270, 38, true, false, 'Item is certified no_beef and no_pork. Contains grilled chicken only as protein. Both restrictions are fully satisfied.', '2026-06-03 10:14:07.051373+00:00'::timestamptz),
(270, 39, true, false, 'Item is certified no_beef and no_pork. Contains chicken only as protein. Both restrictions are fully satisfied.', '2026-06-03 10:14:07.051373+00:00'::timestamptz),
(270, 40, true, false, 'Item is certified no_beef and no_pork. Contains crispy chicken only as protein. Both restrictions are fully satisfied.', '2026-06-03 10:14:07.051373+00:00'::timestamptz),
