INSERT INTO student_eligible_meals (enrolment_id, menu_item_id, eligible, needs_tweak, rationale, computed_at) VALUES
(280, 31, true, false, 'Contents explicitly state no meat and seafood-free. The tweaks note a ''vegetarian option available on request'', but the base item already contains no meat or seafood (egg, cheese, tortilla). Safe as-is for a vegetarian.', '2026-06-03 10:14:07.693562+00:00'::timestamptz),
(280, 32, true, true, 'The base item contains anchovy dressing, which is seafood and therefore not vegetarian. However, the tweaks_text states ''Can omit anchovy dressing on request'', which removes the offending ingredient.', '2026-06-03 10:14:07.693562+00:00'::timestamptz),
(280, 33, true, true, 'The base item contains ''protein (type unspecified)'', which cannot be assumed to be vegetarian. However, tweaks_text states ''Vegetarian option available on request'', which removes the unspecified protein and makes it safe for a vegetarian.', '2026-06-03 10:14:07.693562+00:00'::timestamptz),
(280, 34, true, true, 'The base item contains grilled chicken, which is meat and not vegetarian. Tweaks_text states ''Vegetarian option available on request'', which would remove the chicken and make it safe for a vegetarian.', '2026-06-03 10:14:07.693562+00:00'::timestamptz),
(280, 35, false, false, 'Contains pulled pork, which is meat. No tweak is available to remove it.', '2026-06-03 10:14:07.693562+00:00'::timestamptz),
(280, 36, true, true, 'The base item contains seasoned meat (unspecified protein), which is not vegetarian. Tweaks_text states ''Vegetarian option available on request (beans instead of meat)'', which removes the meat and makes it safe for a vegetarian.', '2026-06-03 10:14:07.693562+00:00'::timestamptz),
(280, 37, true, true, 'The base item contains seasoned meat (unspecified protein), which is not vegetarian. Tweaks_text states ''Vegetarian option available on request (beans instead of meat)'', which removes the meat and makes it safe for a vegetarian.', '2026-06-03 10:14:07.693562+00:00'::timestamptz),
(280, 38, false, false, 'Contains grilled chicken, which is meat. No tweak is available to remove it.', '2026-06-03 10:14:07.693562+00:00'::timestamptz),
