(303, 31, true, false, 'Item is certified halal. No pork or non-halal meat present (no meat at all). All contents are halal-compatible and the item carries halal certification.', '2026-06-03 10:13:56.854181+00:00'::timestamptz),
(303, 32, true, false, 'Item is certified halal. Anchovy dressing raises a seafood concern but halal certification is explicitly stated. The student''s only requirement is halal, and the item is certified to satisfy halal.', '2026-06-03 10:13:56.854181+00:00'::timestamptz),
(303, 33, false, false, 'Protein type is unspecified and must be treated as unsafe for halal. The item is NOT certified halal (only certified no_seafood). No tweak resolves the halal concern — the vegetarian option removes the meat but the item still lacks halal certification overall.', '2026-06-03 10:13:56.854181+00:00'::timestamptz),
(303, 34, true, false, 'Item is certified halal. Contains grilled chicken (halal), flour tortilla, rice, and cheese. Satisfies the student''s halal requirement.', '2026-06-03 10:13:56.854181+00:00'::timestamptz),
(303, 35, false, false, 'Contains pulled pork, which is explicitly non-halal (pork is forbidden). Item is not certified halal. No tweak is available to remove the pork.', '2026-06-03 10:13:56.854181+00:00'::timestamptz),
(303, 36, true, true, 'Seasoned meat is unspecified and not halal-certified; item is NOT certified halal as-is. However, the stated tweak (vegetarian option with beans instead of meat) removes the non-halal risk. With this tweak the item contains only corn chips, cheese, and beans — no halal-violating ingredient.', '2026-06-03 10:13:56.854181+00:00'::timestamptz),
(303, 37, true, true, 'Seasoned meat is unspecified and not halal-certified; item is NOT certified halal as-is. However, the stated tweak (vegetarian option with beans instead of meat) removes the non-halal risk. With this tweak the item contains only fries, cheese, and beans — no halal-violating ingredient.', '2026-06-03 10:13:56.854181+00:00'::timestamptz),
(303, 38, true, false, 'Item is certified halal. Contains grilled chicken (halal), flour tortilla, and cheese. Satisfies the student''s halal requirement.', '2026-06-03 10:13:56.854181+00:00'::timestamptz),
(303, 39, true, false, 'Item is explicitly certified halal. Contains halal chicken, corn tortilla, enchilada sauce, and rice. Satisfies the student''s halal requirement.', '2026-06-03 10:13:56.854181+00:00'::timestamptz),
(303, 40, true, false, 'Item is certified halal. Contains crispy chicken (halal), tortilla, and cheese. Satisfies the student''s halal requirement.', '2026-06-03 10:13:56.854181+00:00'::timestamptz),
